{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        // Task.Run uses the thread pool — no need for manual Thread creation.
        // The CancellationToken is passed into the loop for cooperative shutdown.
        _workerTask = Task.Run(() => ProcessLoop(_cts.Token));
    }

    private void ProcessLoop(CancellationToken ct)
    {
        // Check the token instead of a volatile bool.
        while (!ct.IsCancellationRequested)
        {
            try
            {
                // Pass the token to blocking calls so they can be interrupted.
                // This is the critical difference — the old Abort() forced
                // interruption from outside; now the callee must cooperate.
                var item = GetNextItem(ct);
                ProcessItem(item);
            }
            catch (OperationCanceledException) when (ct.IsCancellationRequested)
            {
                // Equivalent to the old ThreadAbortException handler.
                // Unlike ThreadAbortException, this does NOT auto-rethrow,
                // so there is no need for ResetAbort(). The loop will exit
                // naturally because ct.IsCancellationRequested is true.
                RollbackCurrentTransaction();
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

