                // a managed thread. If you reach here, GetNextItem or
                // ProcessItem is not honoring the CancellationToken.
                // Fix the root cause; don't look for an Abort() equivalent.
                Console.Error.WriteLine(
                    "WARNING: BackgroundProcessor did not stop within timeout. " +
                    "Ensure all blocking calls accept CancellationToken.");
            }
        }
    }

