    public async Task StopAsync()
    {
        _cts.Cancel();
        if (_workerTask != null)
        {
            // Gracefully await with a timeout.
            using var timeoutCts = new CancellationTokenSource(TimeSpan.FromSeconds(5));
            try
            {
                await _workerTask.WaitAsync(timeoutCts.Token);
            }
            catch (OperationCanceledException)
            {
                Console.Error.WriteLine(
                    "WARNING: BackgroundProcessor did not stop within timeout.");
            }
        }
    }

    public void Dispose()
    {
        Stop();
        _cts.Dispose();
    }

    // --- Stubs for illustration (replace with your real implementations) ---

    /// <summary>
    /// MIGRATION NOTE: Your real GetNextItem() must accept a CancellationToken.
    /// 
    /// Common patterns:
